(function(){const t={},s=document.querySelectorAll(".post-card[data-tags]");s.forEach(e=>{const n=e.getAttribute("data-tags").split(",").filter(e=>e.trim());n.forEach(n=>{t[n]||(t[n]=[]),t[n].push(e)})});const e=document.getElementById("tagFilter");if(!e)return;const o=Object.keys(t);if(o.length===0){e.style.display="none";return}const n=document.createElement("button");n.className="tag active",n.textContent="全部",n.dataset.tag="all",e.appendChild(n),o.forEach(t=>{const n=document.createElement("button");n.className="tag",n.textContent=t,n.dataset.tag=t,e.appendChild(n)}),e.addEventListener("click",t=>{if(t.target.classList.contains("tag")){e.querySelectorAll(".tag").forEach(e=>e.classList.remove("active")),t.target.classList.add("active");const n=t.target.dataset.tag;s.forEach(e=>{if(n==="all")e.style.display="";else{const t=e.getAttribute("data-tags").split(",").map(e=>e.trim());t.includes(n)?e.style.display="":e.style.display="none"}})}})})()